firmware_template.source:
#include "ccs811.h"
#include <Wire.h>
#include <Adafruit_CCS811.h>
static Adafruit_CCS811 ccs;
static uint16_t _eco2=0,_tvoc=0;static unsigned long _l=0;
void ccs811_setup(){Wire.begin();if(!ccs.begin()){Serial.println("[ccs811] Fail!");return;}while(!ccs.available());Serial.println("[ccs811] OK");}
void ccs811_loop(){if(millis()-_l<1000)return;_l=millis();if(ccs.available()&&!ccs.readData()){_eco2=ccs.geteCO2();_tvoc=ccs.getTVOC();}}
uint16_t ccs811_get_eco2(){return _eco2;}
uint16_t ccs811_get_tvoc(){return _tvoc;}
